import { useMemo } from 'react'
import { graphql } from 'gql.tada'
import { useQuery } from '@/lib/graphql'

export interface DataSource {
  id: string
  name: string
  shortName: string
  dataset: string
  url: string
  description: string
  fields: string[]
}

const DataSourcesQuery = graphql(`
  query DataSources {
    dataSources {
      id
      name
      shortName
      dataset
      url
      description
      fields
    }
  }
`)

/**
 * Fetches the data source catalog once and returns a Map keyed by source ID.
 */
export function useDataSources(): Map<string, DataSource> {
  const [result] = useQuery<{ dataSources: DataSource[] }>({
    query: DataSourcesQuery,
  })

  return useMemo(() => {
    const map = new Map<string, DataSource>()
    for (const ds of result.data?.dataSources ?? []) {
      map.set(ds.id, ds)
    }
    return map
  }, [result.data?.dataSources])
}

import { useState, useCallback } from 'react'
import { graphql } from 'gql.tada'
import { useQuery } from '@/lib/graphql'
import { TextInput, Button, Group, Text, Stack } from '@mantine/core'
import { MapPin, X, Loader2 } from 'lucide-react'

export interface UserLocationValue {
  latitude: number
  longitude: number
  state?: string
  displayName?: string
}

const ResolveZipQuery = graphql(`
  query ResolveZip($zip: String!) {
    resolveZip(zip: $zip) {
      zip
      latitude
      longitude
      state
      city
    }
  }
`)

export interface LocationInputProps {
  value: UserLocationValue | undefined
  onChange: (loc: UserLocationValue | undefined) => void
}

export function LocationInput({ value, onChange }: LocationInputProps) {
  const [zipInput, setZipInput] = useState('')
  const [zipError, setZipError] = useState<string | undefined>()
  const [geoLoading, setGeoLoading] = useState(false)

  const zipToResolve = /^\d{5}$/.test(zipInput) ? zipInput : null

  const [zipResult] = useQuery<{
    resolveZip: { zip: string; latitude: number; longitude: number; state: string; city: string } | null
  }>({
    query: ResolveZipQuery,
    variables: { zip: zipToResolve ?? '' },
    pause: !zipToResolve,
  })

  const handleZipSubmit = useCallback(() => {
    if (!/^\d{5}$/.test(zipInput)) {
      setZipError('Enter a 5-digit ZIP code')
      return
    }
    setZipError(undefined)

    if (zipResult.data?.resolveZip) {
      const z = zipResult.data.resolveZip
      onChange({
        latitude: z.latitude,
        longitude: z.longitude,
        state: z.state,
        displayName: `${z.city}, ${z.state}`,
      })
    } else if (zipResult.fetching) {
      // Wait for result — user will need to submit again
      setZipError('Looking up ZIP code…')
    } else {
      setZipError('ZIP code not found')
    }
  }, [zipInput, zipResult, onChange])

  const handleGeolocation = useCallback(() => {
    if (!navigator.geolocation) {
      setZipError('Geolocation not supported')
      return
    }
    setGeoLoading(true)
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setGeoLoading(false)
        onChange({
          latitude: pos.coords.latitude,
          longitude: pos.coords.longitude,
          displayName: `${pos.coords.latitude.toFixed(2)}°, ${pos.coords.longitude.toFixed(2)}°`,
        })
      },
      () => {
        setGeoLoading(false)
        setZipError('Could not get your location')
      },
    )
  }, [onChange])

  const handleClear = useCallback(() => {
    onChange(undefined)
    setZipInput('')
    setZipError(undefined)
  }, [onChange])

  if (value) {
    return (
      <Group gap="xs">
        <MapPin size={14} />
        <Text size="sm" fw={500}>
          {value.displayName ?? `${value.latitude.toFixed(2)}°, ${value.longitude.toFixed(2)}°`}
        </Text>
        <Button variant="subtle" size="compact-xs" onClick={handleClear} aria-label="Clear location">
          <X size={12} />
        </Button>
      </Group>
    )
  }

  return (
    <Stack gap="xs">
      <Group gap="xs" align="flex-end">
        <TextInput
          label="ZIP code"
          placeholder="e.g. 02134"
          value={zipInput}
          onChange={(e) => {
            setZipInput(e.currentTarget.value)
            setZipError(undefined)
          }}
          onKeyDown={(e) => {
            if (e.key === 'Enter') handleZipSubmit()
          }}
          error={zipError}
          size="xs"
          style={{ flex: 1 }}
        />
        <Button size="xs" onClick={handleZipSubmit} disabled={zipResult.fetching}>
          Go
        </Button>
      </Group>
      <Button
        variant="light"
        size="xs"
        leftSection={geoLoading ? <Loader2 size={14} /> : <MapPin size={14} />}
        onClick={handleGeolocation}
        disabled={geoLoading}
      >
        Use my location
      </Button>
    </Stack>
  )
}

import { Text, Group, Loader, Center, Card, Badge, SimpleGrid } from '@mantine/core'
import { graphql } from 'gql.tada'
import { useQuery } from '@/lib/graphql'

const SimilarInstitutionsQuery = graphql(`
  query SimilarInstitutions($unitID: String!, $limit: Int) {
    similarInstitutions(unitID: $unitID, limit: $limit) {
      unitID
      name
      city
      state
      distance
      institutionType
      enrollment
      admissionRate
      graduationRate
      inStateTuition
      outOfStateTuition
    }
  }
`)

interface SimilarInstitution {
  unitID: string
  name: string
  city: string
  state: string
  distance: number
  institutionType: string | null
  enrollment: number | null
  admissionRate: number | null
  graduationRate: number | null
  inStateTuition: number | null
  outOfStateTuition: number | null
}

interface SimilarInstitutionsData {
  similarInstitutions: SimilarInstitution[]
}

const INSTITUTION_TYPES: Record<string, string> = {
  '1': 'Public',
  '2': 'Private nonprofit',
  '3': 'Private for-profit',
}

interface SimilarInstitutionsProps {
  unitID: string
  onSelect?: (unitID: string) => void
}

export function SimilarInstitutions({ unitID, onSelect }: SimilarInstitutionsProps) {
  const [result] = useQuery<SimilarInstitutionsData>({
    query: SimilarInstitutionsQuery,
    variables: { unitID, limit: 6 },
  })

  if (result.fetching) {
    return (
      <Center py="md">
        <Loader size="sm" />
      </Center>
    )
  }

  if (result.error) {
    return (
      <Text c="red" size="sm">
        Failed to load similar institutions.
      </Text>
    )
  }

  const institutions = result.data?.similarInstitutions ?? []

  if (institutions.length === 0) {
    return (
      <Text c="dimmed" size="sm">
        No similar institutions found.
      </Text>
    )
  }

  return (
    <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="sm">
      {institutions.map((inst) => (
        <Card
          key={inst.unitID}
          padding="sm"
          radius="sm"
          withBorder
          style={{ cursor: onSelect ? 'pointer' : undefined }}
          onClick={onSelect ? () => onSelect(inst.unitID) : undefined}
        >
          <Text size="sm" fw={600} lineClamp={1}>
            {inst.name}
          </Text>
          <Text size="xs" c="dimmed">
            {inst.city}, {inst.state}
          </Text>
          <Group gap="xs" mt="xs">
            {inst.institutionType && (
              <Badge size="xs" variant="light">
                {INSTITUTION_TYPES[inst.institutionType] ?? inst.institutionType}
              </Badge>
            )}
            {inst.enrollment != null && (
              <Badge size="xs" variant="light" color="gray">
                {inst.enrollment.toLocaleString()} students
              </Badge>
            )}
          </Group>
          <Group gap="md" mt="xs">
            {inst.admissionRate != null && (
              <Text size="xs" c="dimmed">
                Admit: {(inst.admissionRate * 100).toFixed(0)}%
              </Text>
            )}
            {inst.graduationRate != null && (
              <Text size="xs" c="dimmed">
                Grad: {(inst.graduationRate * 100).toFixed(0)}%
              </Text>
            )}
            {inst.inStateTuition != null && (
              <Text size="xs" c="dimmed">
                Tuition: ${inst.inStateTuition.toLocaleString()}
              </Text>
            )}
          </Group>
        </Card>
      ))}
    </SimpleGrid>
  )
}

